const fs = require('fs');
const path = require('path');
const home = require('os').homedir();
const base = path.join(home, 'Library', 'Application Support', 'Local');

// Common electron-store / Local patterns for userData storage
const candidates = [
  'userData.json',
  'nexus-ai.json',
  'addon-data.json',
  'plugin-data.json',
  'storage.json',
  'local-addon-nexus-ai.json',
  'app-data.json',
];

for (const f of candidates) {
  const full = path.join(base, f);
  if (fs.existsSync(full)) {
    console.log('FOUND:', full);
    const raw = fs.readFileSync(full, 'utf8');
    if (raw.includes('nexus_ai_gateway_usage')) {
      console.log('  --> contains gateway usage data!');
    }
  }
}

// Also check one level deeper
try {
  const entries = fs.readdirSync(base);
  console.log('Base dir contents:', entries.join(', '));
} catch(e) {
  console.log('Could not read base dir:', e.message);
}
